                int overlapX = Math.max(0, Math.min(x2, x4) - Math.max(x1, x3));
                int overlapY = Math.max(0, Math.min(y2, y4) - Math.max(y1, y3));
                area2 = (x4 - x3) * (y4 - y3) - overlapX * overlapY;
